fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val teleportList = Array(m) { Array(n) { mutableListOf<Pair<Int, Int>>() } }
    for (i in 0 until m) {
        for (j in 0 until n) {
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].add(Pair(x, y))
                    }
                }
            }
        }
    }

    val dist = Array(m) { Array(n) { Array(k.toInt() + 1) { Long.MAX_VALUE } } }
    dist[0][0][0] = 0L
    val pq = PriorityQueue<Triple<Long, Int, Int, Long>>(compareBy { it.first })

    pq.add(Triple(0L, 0, 0, 0L))

    while (pq.isNotEmpty()) {
        val (currentCost, i, j, t) = pq.poll()
        if (i == m - 1 && j == n - 1) return currentCost
        if (currentCost > dist[i][j][t.toInt()]) continue

        if (j + 1 < n) {
            val newCost = currentCost + grid[i][j + 1]
            if (newCost < dist[i][j + 1][t.toInt()]) {
                dist[i][j + 1][t.toInt()] = newCost
                pq.add(Triple(newCost, i, j + 1, t))
            }
        }

        if (i + 1 < m) {
            val newCost = currentCost + grid[i + 1][j]
            if (newCost < dist[i + 1][j][t.toInt()]) {
                dist[i + 1][j][t.toInt()] = newCost
                pq.add(Triple(newCost, i + 1, j, t))
            }
        }

        if (t < k) {
            for (pair in teleportList[i][j]) {
                val (x, y) = pair
                val newT = t + 1
                if (currentCost < dist[x][y][newT.toInt()]) {
                    dist[x][y][newT.toInt()] = currentCost
                    pq.add(Triple(currentCost, x, y, newT))
                }
            }
        }
    }

    return -1L
}
